from pathlib import Path
import pytest
from paths import safe_join

def test_child(tmp_path): assert safe_join(tmp_path, 'a/b') == (tmp_path/'a/b').resolve()
def test_parent(tmp_path):
    with pytest.raises(ValueError): safe_join(tmp_path, '../escape')
def test_absolute(tmp_path):
    with pytest.raises(ValueError): safe_join(tmp_path, '/etc/passwd')
def test_symlink(tmp_path):
    outside = tmp_path.parent / 'outside'; outside.mkdir(exist_ok=True)
    (tmp_path/'link').symlink_to(outside, target_is_directory=True)
    with pytest.raises(ValueError): safe_join(tmp_path, 'link/file')

