import test from 'node:test'; import assert from 'node:assert/strict';
import {getOrLoad, clear} from './cache.mjs';
test('deduplicates', async () => { clear(); let calls=0; const load=async()=>{calls++; await new Promise(r=>setTimeout(r,10)); return 7}; assert.deepEqual(await Promise.all([getOrLoad('x',load),getOrLoad('x',load)]),[7,7]); assert.equal(calls,1); });
test('retries failures', async () => { clear(); let calls=0; const load=async()=>{calls++; if(calls===1) throw Error('x'); return 9}; await assert.rejects(getOrLoad('x',load)); assert.equal(await getOrLoad('x',load),9); });

