#[derive(Clone,Copy,Debug,PartialEq)] pub enum State { Queued, Running, Finished }
pub struct Job { pub state: State }
impl Job { pub fn transition(&mut self, next: State) -> bool { self.state=next; true } }
#[cfg(test)] mod tests { use super::*; #[test] fn valid(){let mut j=Job{state:State::Queued};assert!(j.transition(State::Running));assert!(j.transition(State::Finished));} #[test] fn invalid(){let mut j=Job{state:State::Queued};assert!(!j.transition(State::Finished));assert_eq!(j.state,State::Queued);} }
